import{_ as t,o as r,c as a,ai as i}from"./chunks/framework.CaiDwmc7.js";const g=JSON.parse('{"title":"Python 开源项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/python-projects.md","filePath":"open-source/python-projects.md"}'),e={name:"open-source/python-projects.md"};function o(n,l,h,s,u,p){return r(),a("div",null,[...l[0]||(l[0]=[i('<h1 id="python-开源项目" tabindex="-1">Python 开源项目 <a class="header-anchor" href="#python-开源项目" aria-label="Permalink to “Python 开源项目”">​</a></h1><p>本页面精选了优秀的Python开源项目，包括Web框架、数据科学、机器学习、自动化工具等。</p><h2 id="web-框架" tabindex="-1">Web 框架 <a class="header-anchor" href="#web-框架" aria-label="Permalink to “Web 框架”">​</a></h2><h3 id="全栈框架" tabindex="-1">全栈框架 <a class="header-anchor" href="#全栈框架" aria-label="Permalink to “全栈框架”">​</a></h3><ul><li><p><strong>Django</strong>：高水平全栈Web框架</p><ul><li>GitHub: <a href="https://github.com/django/django" target="_blank" rel="noreferrer">https://github.com/django/django</a></li><li>特点: MTV架构、自带Admin、ORM、安全性高</li><li>适用: 企业级应用、CMS系统</li></ul></li><li><p><strong>Flask</strong>：轻量级Web框架</p><ul><li>GitHub: <a href="https://github.com/pallets/flask" target="_blank" rel="noreferrer">https://github.com/pallets/flask</a></li><li>特点: 微框架、扩展性强、简单灵活</li><li>适用: API开发、小型应用</li></ul></li><li><p><strong>FastAPI</strong>：现代异步Web框架</p><ul><li>GitHub: <a href="https://github.com/tiangolo/fastapi" target="_blank" rel="noreferrer">https://github.com/tiangolo/fastapi</a></li><li>特点: 异步支持、自动API文档、类型提示</li><li>适用: 高性能API、微服务</li></ul></li></ul><h3 id="异步框架" tabindex="-1">异步框架 <a class="header-anchor" href="#异步框架" aria-label="Permalink to “异步框架”">​</a></h3><ul><li><p><strong>Tornado</strong>：异步Web框架</p><ul><li>GitHub: <a href="https://github.com/tornadoweb/tornado" target="_blank" rel="noreferrer">https://github.com/tornadoweb/tornado</a></li><li>特点: 非阻塞I/O、高并发处理</li><li>适用: 实时应用、WebSocket</li></ul></li><li><p><strong>Sanic</strong>：异步Web框架</p><ul><li>GitHub: <a href="https://github.com/sanic-org/sanic" target="_blank" rel="noreferrer">https://github.com/sanic-org/sanic</a></li><li>特点: 基于uvloop、性能极高</li><li>适用: 高性能Web应用</li></ul></li></ul><h2 id="数据科学与机器学习" tabindex="-1">数据科学与机器学习 <a class="header-anchor" href="#数据科学与机器学习" aria-label="Permalink to “数据科学与机器学习”">​</a></h2><h3 id="数据处理" tabindex="-1">数据处理 <a class="header-anchor" href="#数据处理" aria-label="Permalink to “数据处理”">​</a></h3><ul><li><p><strong>pandas</strong>：数据分析和处理库</p><ul><li>GitHub: <a href="https://github.com/pandas-dev/pandas" target="_blank" rel="noreferrer">https://github.com/pandas-dev/pandas</a></li><li>功能: DataFrame操作、数据清洗、时间序列</li></ul></li><li><p><strong>NumPy</strong>：数值计算库</p><ul><li>GitHub: <a href="https://github.com/numpy/numpy" target="_blank" rel="noreferrer">https://github.com/numpy/numpy</a></li><li>功能: 多维数组、数学函数、线性代数</li></ul></li><li><p><strong>SciPy</strong>：科学计算库</p><ul><li>GitHub: <a href="https://github.com/scipy/scipy" target="_blank" rel="noreferrer">https://github.com/scipy/scipy</a></li><li>功能: 优化、积分、信号处理</li></ul></li></ul><h3 id="机器学习" tabindex="-1">机器学习 <a class="header-anchor" href="#机器学习" aria-label="Permalink to “机器学习”">​</a></h3><ul><li><p><strong>scikit-learn</strong>：经典机器学习库</p><ul><li>GitHub: <a href="https://github.com/scikit-learn/scikit-learn" target="_blank" rel="noreferrer">https://github.com/scikit-learn/scikit-learn</a></li><li>功能: 分类、回归、聚类、降维</li></ul></li><li><p><strong>TensorFlow</strong>：深度学习框架</p><ul><li>GitHub: <a href="https://github.com/tensorflow/tensorflow" target="_blank" rel="noreferrer">https://github.com/tensorflow/tensorflow</a></li><li>特点: 生产级、分布式训练、移动端支持</li></ul></li><li><p><strong>PyTorch</strong>：深度学习框架</p><ul><li>GitHub: <a href="https://github.com/pytorch/pytorch" target="_blank" rel="noreferrer">https://github.com/pytorch/pytorch</a></li><li>特点: 动态图、易用性好、研究友好</li></ul></li></ul><h3 id="数据可视化" tabindex="-1">数据可视化 <a class="header-anchor" href="#数据可视化" aria-label="Permalink to “数据可视化”">​</a></h3><ul><li><p><strong>Matplotlib</strong>：绘图库</p><ul><li>GitHub: <a href="https://github.com/matplotlib/matplotlib" target="_blank" rel="noreferrer">https://github.com/matplotlib/matplotlib</a></li><li>功能: 2D/3D绘图、统计图表</li></ul></li><li><p><strong>Seaborn</strong>：统计数据可视化</p><ul><li>GitHub: <a href="https://github.com/mwaskom/seaborn" target="_blank" rel="noreferrer">https://github.com/mwaskom/seaborn</a></li><li>功能: 统计图表、美观样式</li></ul></li><li><p><strong>Plotly</strong>：交互式图表</p><ul><li>GitHub: <a href="https://github.com/plotly/plotly.py" target="_blank" rel="noreferrer">https://github.com/plotly/plotly.py</a></li><li>功能: Web交互图表、仪表板</li></ul></li></ul><h2 id="自动化与爬虫" tabindex="-1">自动化与爬虫 <a class="header-anchor" href="#自动化与爬虫" aria-label="Permalink to “自动化与爬虫”">​</a></h2><h3 id="web爬虫" tabindex="-1">Web爬虫 <a class="header-anchor" href="#web爬虫" aria-label="Permalink to “Web爬虫”">​</a></h3><ul><li><p><strong>Scrapy</strong>：专业爬虫框架</p><ul><li>GitHub: <a href="https://github.com/scrapy/scrapy" target="_blank" rel="noreferrer">https://github.com/scrapy/scrapy</a></li><li>功能: 分布式爬取、数据提取、管道处理</li></ul></li><li><p><strong>Beautiful Soup</strong>：HTML解析库</p><ul><li>GitHub: <a href="https://github.com/w3c/BeautifulSoup4" target="_blank" rel="noreferrer">https://github.com/w3c/BeautifulSoup4</a></li><li>功能: HTML/XML解析、数据提取</li></ul></li><li><p><strong>Selenium</strong>：Web自动化测试</p><ul><li>GitHub: <a href="https://github.com/SeleniumHQ/selenium" target="_blank" rel="noreferrer">https://github.com/SeleniumHQ/selenium</a></li><li>功能: 浏览器自动化、Web测试</li></ul></li></ul><h3 id="自动化工具" tabindex="-1">自动化工具 <a class="header-anchor" href="#自动化工具" aria-label="Permalink to “自动化工具”">​</a></h3><ul><li><p><strong>Ansible</strong>：自动化运维工具</p><ul><li>GitHub: <a href="https://github.com/ansible/ansible" target="_blank" rel="noreferrer">https://github.com/ansible/ansible</a></li><li>功能: 配置管理、应用部署</li></ul></li><li><p><strong>Fabric</strong>：Python自动化部署</p><ul><li>GitHub: <a href="https://github.com/fabric/fabric" target="_blank" rel="noreferrer">https://github.com/fabric/fabric</a></li><li>功能: SSH执行、文件传输</li></ul></li></ul><h2 id="工具库" tabindex="-1">工具库 <a class="header-anchor" href="#工具库" aria-label="Permalink to “工具库”">​</a></h2><h3 id="http客户端" tabindex="-1">HTTP客户端 <a class="header-anchor" href="#http客户端" aria-label="Permalink to “HTTP客户端”">​</a></h3><ul><li><p><strong>requests</strong>：HTTP库</p><ul><li>GitHub: <a href="https://github.com/psf/requests" target="_blank" rel="noreferrer">https://github.com/psf/requests</a></li><li>功能: HTTP请求、会话管理、SSL验证</li></ul></li><li><p><strong>httpx</strong>：异步HTTP客户端</p><ul><li>GitHub: <a href="https://github.com/encode/httpx" target="_blank" rel="noreferrer">https://github.com/encode/httpx</a></li><li>功能: 同步/异步HTTP、WebSocket</li></ul></li></ul><h3 id="命令行工具" tabindex="-1">命令行工具 <a class="header-anchor" href="#命令行工具" aria-label="Permalink to “命令行工具”">​</a></h3><ul><li><p><strong>Click</strong>：命令行界面创建工具</p><ul><li>GitHub: <a href="https://github.com/pallets/click" target="_blank" rel="noreferrer">https://github.com/pallets/click</a></li><li>功能: CLI应用开发、参数解析</li></ul></li><li><p><strong>Typer</strong>：基于类型提示的CLI</p><ul><li>GitHub: <a href="https://github.com/tiangolo/typer" target="_blank" rel="noreferrer">https://github.com/tiangolo/typer</a></li><li>功能: 现代化CLI、自动补全</li></ul></li></ul><h2 id="应用项目" tabindex="-1">应用项目 <a class="header-anchor" href="#应用项目" aria-label="Permalink to “应用项目”">​</a></h2><h3 id="cms系统" tabindex="-1">CMS系统 <a class="header-anchor" href="#cms系统" aria-label="Permalink to “CMS系统”">​</a></h3><ul><li><p><strong>Wagtail</strong>：Django CMS</p><ul><li>GitHub: <a href="https://github.com/wagtail/wagtail" target="_blank" rel="noreferrer">https://github.com/wagtail/wagtail</a></li><li>功能: 内容管理、页面编辑</li></ul></li><li><p><strong>Django CMS</strong>：企业级CMS</p><ul><li>GitHub: <a href="https://github.com/django-cms/django-cms" target="_blank" rel="noreferrer">https://github.com/django-cms/django-cms</a></li><li>功能: 模块化设计、多语言支持</li></ul></li></ul><h3 id="api框架" tabindex="-1">API框架 <a class="header-anchor" href="#api框架" aria-label="Permalink to “API框架”">​</a></h3><ul><li><p><strong>Django REST framework</strong>：Django API框架</p><ul><li>GitHub: <a href="https://github.com/encode/django-rest-framework" target="_blank" rel="noreferrer">https://github.com/encode/django-rest-framework</a></li><li>功能: RESTful API、序列化、认证</li></ul></li><li><p><strong>Flask-RESTful</strong>：Flask API扩展</p><ul><li>GitHub: <a href="https://github.com/flask-restful/flask-restful" target="_blank" rel="noreferrer">https://github.com/flask-restful/flask-restful</a></li><li>功能: REST API开发、请求解析</li></ul></li></ul>',29)])])}const c=t(e,[["render",o]]);export{g as __pageData,c as default};
